case class TimestampEntry(
  ts: Long = 0L,
  event: String = "",
  payload: Option[Array[Byte]] = None
)

def writeTimestampEntry(w: SpecWriter, obj: TimestampEntry): Unit = {
  var fieldCount = 2
  obj.payload.foreach { _ => fieldCount += 1 }
  w.beginObject(fieldCount)
  w.writeField("ts"); w.writeInt64(obj.ts)
  w.writeField("event"); w.writeString(obj.event)
  obj.payload.foreach { v => w.writeField("payload"); w.writeBytes(v) }
  w.endObject()
}

def decodeTimestampEntry(r: SpecReader): TimestampEntry = {
  var tsVal: Long = 0L
  var eventVal: String = ""
  var payloadVal: Option[Array[Byte]] = None
  r.beginObject()
  while (r.hasNextField()) {
    r.readFieldName() match {
      case "ts" => tsVal = r.readInt64()
      case "event" => eventVal = r.readString()
      case "payload" => payloadVal = Some(r.readBytes())
      case _ => r.skip()
    }
  }
  r.endObject()
  TimestampEntry(ts = tsVal, event = eventVal, payload = payloadVal)
}

val TimestampEntryCodec = SpecCodec[TimestampEntry](encode = writeTimestampEntry, decode = decodeTimestampEntry)

case class ConfigEntry(
  key: String = "",
  int_value: Option[Int] = None,
  str_value: Option[String] = None,
  bool_value: Option[Boolean] = None,
  float_value: Option[Double] = None
)

def writeConfigEntry(w: SpecWriter, obj: ConfigEntry): Unit = {
  var fieldCount = 1
  obj.int_value.foreach { _ => fieldCount += 1 }
  obj.str_value.foreach { _ => fieldCount += 1 }
  obj.bool_value.foreach { _ => fieldCount += 1 }
  obj.float_value.foreach { _ => fieldCount += 1 }
  w.beginObject(fieldCount)
  w.writeField("key"); w.writeString(obj.key)
  obj.int_value.foreach { v => w.writeField("intValue"); w.writeInt32(v) }
  obj.str_value.foreach { v => w.writeField("strValue"); w.writeString(v) }
  obj.bool_value.foreach { v => w.writeField("boolValue"); w.writeBool(v) }
  obj.float_value.foreach { v => w.writeField("floatValue"); w.writeFloat64(v) }
  w.endObject()
}

def decodeConfigEntry(r: SpecReader): ConfigEntry = {
  var keyVal: String = ""
  var int_valueVal: Option[Int] = None
  var str_valueVal: Option[String] = None
  var bool_valueVal: Option[Boolean] = None
  var float_valueVal: Option[Double] = None
  r.beginObject()
  while (r.hasNextField()) {
    r.readFieldName() match {
      case "key" => keyVal = r.readString()
      case "intValue" => int_valueVal = Some(r.readInt32())
      case "strValue" => str_valueVal = Some(r.readString())
      case "boolValue" => bool_valueVal = Some(r.readBool())
      case "floatValue" => float_valueVal = Some(r.readFloat64())
      case _ => r.skip()
    }
  }
  r.endObject()
  ConfigEntry(key = keyVal, int_value = int_valueVal, str_value = str_valueVal, bool_value = bool_valueVal, float_value = float_valueVal)
}

val ConfigEntryCodec = SpecCodec[ConfigEntry](encode = writeConfigEntry, decode = decodeConfigEntry)
